mapper.select:
SELECT ssp.*, qn.qr_code as qrCode, qn.nickname FROM store_seller_promotion as ssp LEFT JOIN (SELECT a.id, a.prom_id, a.goods_title, b.product_name, b.brand_id, b.brand_name FROM store_promotion_goods a LEFT JOIN kol_product b ON a.kol_product_id = b.id ) spg on ssp.id = spg.prom_id LEFT JOIN store_promotion_goods_celebrity spgc ON spgc.goods_id = spg.id LEFT JOIN store_celebrity_private scp ON spgc.celebrity_private_id = scp.id LEFT JOIN store_user_counselor qn ON ssp.seller_counselor_id = qn.id where ssp.is_del =0
and ssp.product_brand like CONCAT('%', #{storeSellerPromotionModel.productBrand}, '%')
and scp.account like CONCAT('%', #{storeSellerPromotionModel.account}, '%')
and ssp.seller_name like CONCAT('%', #{storeSellerPromotionModel.sellerName}, '%')
and ssp.extension_code like CONCAT('%', #{storeSellerPromotionModel.extensionCode}, '%')
and ssp.prom_status = #{storeSellerPromotionModel.promStatus}
and ssp.prom_tags in
#{item}
and ssp.approved_status = #{storeSellerPromotionModel.approvedStatus}
and ssp.pay_status = #{storeSellerPromotionModel.payStatus}
AND ssp.counselor_user_id = #{storeSellerPromotionModel.counselorUserId}
and ssp.prom_title like CONCAT('%', #{storeSellerPromotionModel.promTitle}, '%')
and spg.goods_title like CONCAT('%', #{storeSellerPromotionModel.goodsTitle}, '%')
and ssp.celebrity_user_id = #{storeSellerPromotionModel.celebrityUserId}
AND spgc.celebrity_counselor_id = #{storeSellerPromotionModel.celebrityCounselorId} and spgc.celebrity_status = 1 AND spgc.is_del = 0
AND spgc.celebrity_prom_status = #{storeSellerPromotionModel.celebrityPromStatus}
AND ssp.promotion_type = 0
and ssp.create_time > '2025-01-01 00:00:00'
group by ssp.id ORDER BY ssp.create_time DESC

SELECT -- 推广单数 COUNT(*) AS prom_count, -- 未开始单数 SUM(IF(prom_status = 0, 1, 0)) AS unstart_count, -- 进行中单数 SUM(IF(prom_status = 10, 1, 0)) AS underway_count, -- 已结束（异常）单数 SUM(IF(prom_status = 90, 1, 0)) AS abnormal_finish_count, -- 已结束（正常）单数 SUM(IF(prom_status = 99, 1, 0)) AS normal_finish_count, -- 只收意向金单数 SUM(IF(intention_amount > 0 AND (payment_amount = 0 OR payment_amount IS NULL), 1, 0)) AS only_intention_count, -- 只收意向金总额 SUM(IF(intention_amount > 0 AND (payment_amount = 0 OR payment_amount IS NULL), intention_amount, 0)) AS only_intention_amount_sum, -- 已付意向金单数 SUM(IF(intention_amount > 0, 1, 0)) AS intention_count, -- 已付意向金总额 SUM(IF(intention_amount > 0, intention_amount, 0)) AS intention_amount_sum, -- 已付订金单数 SUM(IF(payment_amount > 0 AND pay_status < 20, 1, 0)) AS payment_amount_count, -- 已付订金总额 SUM(IF(payment_amount > 0 AND pay_status < 20, payment_amount, 0)) AS payment_amount_sum, -- 已付全款单数 SUM(IF(pay_status = 20, 1, 0)) AS full_payment_amount_count, -- 已付全款总额 SUM(IF(pay_status = 20, payment_amount + intention_amount, 0)) AS full_payment_amount_sum, -- 有退款订单单数 SUM(IF(refund_amount > 0, 1, 0)) AS refund_amount_count, -- 退款总额 SUM(IF(refund_amount > 0, refund_amount, 0)) AS refund_amount_sum, -- 总收入金额 SUM(IF(payment_amount > 0, payment_amount, 0)) + SUM(IF(intention_amount > 0, intention_amount, 0)) - SUM(IF(refund_amount > 0, refund_amount, 0)) AS total_amount_sum FROM store_seller_promotion ssp RIGHT JOIN (SELECT su.id FROM sys_user su LEFT JOIN ( SELECT id, username FROM sys_user WHERE user_type = 3
AND counselor_user_id = #{promotionStatisticsModel.counselorUserId}
AND id = #{promotionStatisticsModel.sid}
) ssu ON ssu.id = su.seller_counselor_id WHERE su.seller_counselor_id IS NOT NULL AND su.seller_counselor_id != '' AND ssu.username IS NOT NULL) qn on qn.id = ssp.seller_id WHERE DATE_FORMAT(ssp.create_time, '%Y-%m-%d') >= DATE_FORMAT(#{promotionStatisticsModel.startDate}, '%Y-%m-%d') AND DATE_FORMAT(ssp.create_time, '%Y-%m-%d') <= DATE_FORMAT(#{promotionStatisticsModel.endDate}, '%Y-%m-%d') AND ssp.is_del = 0

SELECT ssp.counselor_user_id, ssp.counselor_user_name as username, -- 推广单数 COUNT(*) AS prom_count, -- 未开始单数 SUM(IF(prom_status = 0, 1, 0)) AS unstart_count, -- 进行中单数 SUM(IF(prom_status = 10, 1, 0)) AS underway_count, -- 已结束（异常）单数 SUM(IF(prom_status = 90, 1, 0)) AS abnormal_finish_count, -- 已结束（正常）单数 SUM(IF(prom_status = 99, 1, 0)) AS normal_finish_count, -- 只收意向金单数 SUM(IF(intention_amount > 0 AND (payment_amount = 0 OR payment_amount IS NULL), 1, 0)) AS only_intention_count, -- 只收意向金总额 SUM(IF(intention_amount > 0 AND (payment_amount = 0 OR payment_amount IS NULL), intention_amount, 0)) AS only_intention_amount_sum, -- 已付意向金单数 SUM(IF(intention_amount > 0, 1, 0)) AS intention_count, -- 已付意向金总额 SUM(IF(intention_amount > 0, intention_amount, 0)) AS intention_amount_sum, -- 已付订金单数 SUM(IF(payment_amount > 0 AND pay_status < 20, 1, 0)) AS payment_amount_count, -- 已付订金总额 SUM(IF(payment_amount > 0 AND pay_status < 20, payment_amount, 0)) AS payment_amount_sum, -- 已付全款单数 SUM(IF(pay_status = 20, 1, 0)) AS full_payment_amount_count, -- 已付全款总额 SUM(IF(pay_status = 20, payment_amount + intention_amount, 0)) AS full_payment_amount_sum, -- 有退款订单单数 SUM(IF(refund_amount > 0, 1, 0)) AS refund_amount_count, -- 退款总额 SUM(IF(refund_amount > 0, refund_amount, 0)) AS refund_amount_sum, -- 总收入金额 SUM(IF(payment_amount > 0, payment_amount, 0)) + SUM(IF(intention_amount > 0, intention_amount, 0)) - SUM(IF(refund_amount > 0, refund_amount, 0)) AS total_amount_sum FROM store_seller_promotion ssp WHERE ssp.is_del = 0
AND ssp.counselor_user_id = #{promotionStatisticsModel.counselorUserId}
AND DATE_FORMAT(ssp.create_time, '%Y-%m-%d') >= DATE_FORMAT(#{promotionStatisticsModel.startDate}, '%Y-%m-%d') AND DATE_FORMAT(ssp.create_time, '%Y-%m-%d') <= DATE_FORMAT(#{promotionStatisticsModel.endDate}, '%Y-%m-%d') GROUP BY ssp.counselor_user_id

SELECT celebrity_user_name as username, celebrity_user_id, -- 推广单数 COUNT(*) AS prom_count, -- 未开始单数 SUM(IF(prom_status = 0, 1, 0)) AS unstart_count, -- 进行中单数 SUM(IF(prom_status = 10, 1, 0)) AS underway_count, -- 已结束（异常）单数 SUM(IF(prom_status = 90, 1, 0)) AS abnormal_finish_count, -- 已结束（正常）单数 SUM(IF(prom_status = 99, 1, 0)) AS normal_finish_count, -- 只收意向金单数 SUM(IF(intention_amount > 0 AND (payment_amount = 0 OR payment_amount IS NULL), 1, 0)) AS only_intention_count, -- 只收意向金总额 SUM(IF(intention_amount > 0 AND (payment_amount = 0 OR payment_amount IS NULL), intention_amount, 0)) AS only_intention_amount_sum, -- 已付意向金单数 SUM(IF(intention_amount > 0, 1, 0)) AS intention_count, -- 已付意向金总额 SUM(IF(intention_amount > 0, intention_amount, 0)) AS intention_amount_sum, -- 已付订金单数 SUM(IF(payment_amount > 0 AND pay_status < 20, 1, 0)) AS payment_amount_count, -- 已付订金总额 SUM(IF(payment_amount > 0 AND pay_status < 20, payment_amount, 0)) AS payment_amount_sum, -- 已付全款单数 SUM(IF(pay_status = 20, 1, 0)) AS full_payment_amount_count, -- 已付全款总额 SUM(IF(pay_status = 20, payment_amount + intention_amount, 0)) AS full_payment_amount_sum, -- 有退款订单单数 SUM(IF(refund_amount > 0, 1, 0)) AS refund_amount_count, -- 退款总额 SUM(IF(refund_amount > 0, refund_amount, 0)) AS refund_amount_sum, -- 总收入金额 SUM(IF(payment_amount > 0, payment_amount, 0)) + SUM(IF(intention_amount > 0, intention_amount, 0)) - SUM(IF(refund_amount > 0, refund_amount, 0)) AS total_amount_sum from store_seller_promotion WHERE celebrity_user_id is not null and celebrity_user_name is not null AND is_del = 0 AND DATE_FORMAT(create_time, '%Y-%m-%d') >= DATE_FORMAT(#{promotionStatisticsModel.startDate}, '%Y-%m-%d') AND DATE_FORMAT(create_time, '%Y-%m-%d') <= DATE_FORMAT(#{promotionStatisticsModel.endDate}, '%Y-%m-%d')
AND celebrity_user_id = #{promotionStatisticsModel.celebrityUserId}
GROUP BY celebrity_user_id

SELECT sur.counselor_user_id AS counselor_user_id, sur.counselor_user_name AS counselorUserName, su.seller_counselor_name as sellerCounselorName, spp.pay_type, spp.consume_date, ssp.* FROM store_seller_promotion ssp LEFT JOIN sys_user AS su ON ssp.seller_id = su.id LEFT JOIN sys_user AS sur ON sur.id = su.seller_counselor_id LEFT JOIN (SELECT e1.prom_id, e1.pay_type, e1.consume_date FROM store_promotion_payment e1 LEFT JOIN store_promotion_payment e2 ON e1.prom_id = e2.prom_id AND (( e1.consume_date < e2.consume_date ) OR (e1.consume_date = e2.consume_date AND e1.create_time < e2.create_time)) WHERE e1.consume_date is not null GROUP BY e1.id HAVING count(DISTINCT e2.consume_date) < 1) spp ON spp.prom_id = ssp.id
and sur.counselor_user_id = #{promotionStatisticsModel.counselorUserId}
and spp.consume_date > #{promotionStatisticsModel.startPayDate}
and spp.consume_date < #{promotionStatisticsModel.endPayDate}
and spp.pay_type = 1 AND ssp.pay_status < 20
and (ssp.intention_amount is null or ssp.intention_amount = 0) AND ssp.pay_status = 20
and ssp.intention_amount IS NOT NULL AND ssp.intention_amount > 0 AND ssp.pay_status = 20
and spp.pay_type <> 2 and ssp.pay_status <> 10
and spp.pay_type = 2
and ssp.pay_status < 20 AND spp.consume_date IS NOT NULL and TIMESTAMPDIFF(DAY, spp.consume_date, now()) > 25

SELECT sur.counselor_user_id AS counselor_user_id, sur.counselor_user_name AS counselorUserName, su.seller_counselor_name as sellerCounselorName, spp.pay_type, spp.consume_date, ssp.* FROM store_seller_promotion ssp LEFT JOIN sys_user AS su ON ssp.seller_id = su.id LEFT JOIN sys_user AS sur ON sur.id = su.seller_counselor_id LEFT JOIN (SELECT e1.prom_id, e1.pay_type, e1.consume_date FROM store_promotion_payment e1 LEFT JOIN store_promotion_payment e2 ON e1.prom_id = e2.prom_id AND (( e1.consume_date < e2.consume_date ) OR (e1.consume_date = e2.consume_date AND e1.create_time < e2.create_time)) WHERE e1.consume_date is not null GROUP BY e1.id HAVING count(DISTINCT e2.consume_date) < 1) spp ON spp.prom_id = ssp.id
sur.counselor_user_id is not null
and sur.counselor_user_id = #{promotionStatisticsModel.counselorUserId}
and spp.consume_date > #{promotionStatisticsModel.startPayDate}
and spp.consume_date < #{promotionStatisticsModel.endPayDate}
and spp.pay_type = 1 AND ssp.pay_status < 20
and (ssp.intention_amount is null or ssp.intention_amount = 0) AND ssp.pay_status = 20
and ssp.intention_amount IS NOT NULL AND ssp.intention_amount > 0 AND ssp.pay_status = 20
and spp.pay_type <> 2 and ssp.pay_status <> 10
and spp.pay_type = 2

SELECT sur.counselor_user_id AS counselor_user_id, sur.counselor_user_name AS counselorUserName, su.seller_counselor_name as sellerCounselorName, spp.consume_date, ssp.* FROM store_seller_promotion ssp LEFT JOIN sys_user AS su ON ssp.seller_id = su.id LEFT JOIN sys_user AS sur ON sur.id = su.seller_counselor_id LEFT JOIN (SELECT prom_id, MIN(consume_date) AS consume_date FROM store_promotion_payment AS spp LEFT JOIN store_seller_promotion ssp ON ssp.id = spp.prom_id WHERE ssp.pay_status < 20 AND consume_date IS NOT NULL GROUP BY prom_id) spp ON spp.prom_id = ssp.id
sur.counselor_user_id is not null and TIMESTAMPDIFF(DAY, spp.consume_date, now()) > 25
and sur.counselor_user_id = #{promotionStatisticsModel.counselorUserId}

SELECT sur.counselor_user_id AS counselor_user_id, sur.counselor_user_name AS counselorUserName, su.seller_counselor_name as sellerCounselorName, spp.consume_date, ssp.* FROM store_seller_promotion ssp LEFT JOIN sys_user AS su ON ssp.seller_id = su.id LEFT JOIN sys_user AS sur ON sur.id = su.seller_counselor_id LEFT JOIN (SELECT prom_id, MIN(consume_date) AS consume_date FROM store_promotion_payment AS spp LEFT JOIN store_seller_promotion ssp ON ssp.id = spp.prom_id WHERE ssp.pay_status < 20 AND consume_date IS NOT NULL GROUP BY prom_id) spp ON spp.prom_id = ssp.id
sur.counselor_user_id is not null and TIMESTAMPDIFF(DAY, spp.consume_date, now()) > 25
and sur.counselor_user_id = #{promotionStatisticsModel.counselorUserId}

SELECT ssp.id, ssp.extension_code AS extensionCode, ssp.prom_title AS promTitle FROM store_seller_promotion ssp WHERE ssp.is_del != 1 AND ssp.promotion_type = 1 AND ssp.prom_status != 99 AND ssp.prom_status != 90
and ssp.seller_id = #{storeSellerPromotionModel.sellerId}
and ssp.prom_title like CONCAT('%', #{storeSellerPromotionModel.promTitle}, '%')
and ssp.extension_code like '%${storeSellerPromotionModel.extensionCode}%'
AND ssp.counselor_user_id = #{storeSellerPromotionModel.counselorUserId}
AND ssp.seller_counselor_id = #{storeSellerPromotionModel.sellerCounselorId}
ORDER BY ssp.create_time DESC
